	.TITLE	TESTGRA	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	BIOS	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers; Variables; ---------	.LOC	0OFLAGS:	.BLKB	2		; flags diversOBWRITE:.BLKB	20LGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flagsCHOIX:	.W	LIB,?AFTIM	.ASCIZ	"(W)hole, (C)lip, (S)top, (R)ound, (END) : "	.EVEN	.W	LIB,?GETCAR	.W	LIB,?MINMAJ	.W	LIB,?AFCODE	.W	LIB,?AFCR	LOAD.B	D4,#GRAWHOLE	COMP.W	D3,#'W	JUMP,EQ	10$	LOAD.B	D4,#GRACLIP	COMP.W	D3,#'C	JUMP,EQ	10$	LOAD.B	D4,#GRASTOP	COMP.W	D3,#'S	JUMP,EQ	10$	LOAD.B	D4,#GRAROUND	COMP.W	D3,#'R	JUMP,EQ	10$	COMP.W	D3,#END	JUMP,EQ	RETOUR	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	JUMP	CHOIX10$:	LOAD.B	D3,#MODGRA	.W	LIB,?AFCAR	LOAD.B	D3,D4	.W	LIB,?AFCAR20$:	.W	LIB,?AFTIM	.ASCIZ	"(L)ine, (C)ircle, (END) : "	.EVEN	.W	LIB,?GETCAR	.W	LIB,?MINMAJ	.W	LIB,?AFCODE	.W	LIB,?AFCR	COMP.W	D3,#'L	JUMP,EQ	LINE	COMP.W	D3,#'C	JUMP,EQ	CIRCLE	COMP.W	D3,#END	JUMP,EQ	RETOUR	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	JUMP	CHOIXLINE:	LOAD.L	A3,#(A6)+OBWRITE+1	LOAD.B	(A3)+0,#DRAWSEG	.W	LIB,?AFTIM	.ASCIZ	"Origine x : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+1,D4	.W	LIB,?AFTIM	.ASCIZ	"Origine y : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+3,D4	.W	LIB,?AFTIM	.ASCIZ	"Longueur x : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+5,D4	.W	LIB,?AFTIM	.ASCIZ	"Longueur y : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+7,D4	LOAD.B	(A3)+9,#SETDOT	LOAD.W	D3,#10	.W	LIB,?STRING	CALL	ERROR	JUMP	LINECIRCLE:	LOAD.L	A3,#(A6)+OBWRITE+1	LOAD.B	(A3)+0,#DRAWARC	.W	LIB,?AFTIM	.ASCIZ	"Centre x : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+1,D4	.W	LIB,?AFTIM	.ASCIZ	"Centre y : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+3,D4	.W	LIB,?AFTIM	.ASCIZ	"Rayon : "	.EVEN	CALL	GETDEC	LOAD.W	(A3)+5,D4	LOAD.W	(A3)+7,#-1	LOAD.B	(A3)+9,#SETDOT	LOAD.W	D3,#10	.W	LIB,?STRING	CALL	ERROR	JUMP	CIRCLEER:	PUSH.W	D7		; sauve l'erreur	.W	LIB,?AFCR	; passe  la ligne	POP.W	D7		; reprend l'erreur	.W	LIB,?AFERROR	; affiche l'erreur	.W	LIB,?GETCAR	; attend une toucheRETOUR:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...GETDEC:	PUSHM.L	D2	CLR.B	D210$:	.W	LIB,?GETDEC	COMP.W	D3,#END	JUMP,EQ	RETOUR	COMP.W	D3,#CR	JUMP,EQ	80$	COMP.W	D3,#'-	JUMP,NE	10$	INC.B	D2	JUMP	10$80$:	TEST.B	D2	JUMP,EQ	90$	NEG.W	D490$:	POPM.L	D2	RETERROR:	TEST.W	D7	JUMP,EQ	90$	.W	LIB,?AFERROR	.W	LIB,?AFCR90$:	RET	.END	START